using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API using HttpClient.
/// HttpClient and ILogger are injected via DI (constructor injection).
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the response body as text.")]
    public async Task<string> FetchApi(
        [Description("The full URL to send a GET request to (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching URL: {Url}", url);

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Received {Length} characters from {Url}", content.Length, url);

        return content;
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
